{"version":3,"file":"respec-geonovum.js","sources":["../js/profile-geonovum.js","../src/core/expose-modules.js","../src/core/pubsubhub.js","../src/core/include-config.js","../src/core/override-configuration.js","../src/core/respec-ready.js","../src/core/post-process.js","../src/core/pre-process.js","../src/core/l10n.js","../src/core/utils.js","../src/core/base-runner.js","../src/core/text-loader.js","../node_modules/idb/build/esm/chunk.js","../node_modules/idb/build/esm/index.js","../node_modules/hyperhtml/esm.js","../js/deps/builds/marked.js","../js/deps/builds/pluralize.js","../src/core/import-maps.js","../src/core/markdown.js","../js/shortcut.js","../src/core/ui.js","../src/core/reindent.js","../src/core/location-hash.js","../src/core/LinterRule.js","../src/core/linter-rules/check-charset.js","../src/core/linter-rules/check-internal-slots.js","../src/core/linter-rules/check-punctuation.js","../src/core/linter.js","../src/core/linter-rules/local-refs-exist.js","../src/core/linter-rules/no-headingless-sections.js","../src/core/linter-rules/no-http-props.js","../src/core/linter-rules/privsec-section.js","../src/core/defaults.js","../src/geonovum/defaults.js","../src/core/style.js","../src/geonovum/style.js","../src/geonovum/l10n.js","../src/core/github.js","../src/core/data-include.js","../src/core/data-transform.js","../src/core/inline-idl-parser.js","../src/core/biblio-db.js","../src/core/biblio.js","../src/core/render-biblio.js","../src/core/inlines.js","../src/core/dfn-map.js","../src/core/dfn.js","../src/core/pluralize.js","../src/core/examples.js","../src/core/issues-notes.js","../src/core/requirements.js","../src/core/best-practices.js","../src/core/figures.js","../src/core/data-cite.js","../src/core/xref-db.js","../src/core/xref.js","../src/core/link-to-dfn.js","../src/core/contrib.js","../src/core/fix-headers.js","../src/core/structure.js","../src/core/informative.js","../src/core/id-headers.js","../src/geonovum/conformance.js","../src/core/exporter.js","..